// Validate required fields before doing anything
const body = $input.first().json.body || $input.first().json;

const name = body.name || body.Name || '';
const email = body.email || body.Email || '';
const message = body.message || body.Message || '';

if (!name || !email) {
  throw new Error('Validation failed: name and email are required fields.');
}

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  throw new Error(`Validation failed: '${email}' is not a valid email address.`);
}

return [{
  json: {
    name: name.trim(),
    email: email.trim().toLowerCase(),
    message: message.trim(),
    submittedAt: new Date().toISOString()
  }
}];

// Mock Google Sheets lookup
// In production: replace with Google Sheets node using 'Read Rows' + filter by email

const email = $input.first().json.email;

// Simulated existing contacts in the sheet
const mockSheet = [
  { email: 'existing@example.com', name: 'Existing User', addedAt: '2024-01-01' },
  { email: 'test@canonical.com', name: 'Test Contact', addedAt: '2024-03-15' }
];

const existingContact = mockSheet.find(row => row.email === email);

return [{
  json: {
    ...$input.first().json,
    alreadyExists: !!existingContact,
    existingSince: existingContact ? existingContact.addedAt : null
  }
}];

// Mock adding a new row to Google Sheet
// In production: replace with Google Sheets node 'Append Row'

const contact = $input.first().json;

// Simulate the row being appended
const newRow = {
  name: contact.name,
  email: contact.email,
  message: contact.message,
  addedAt: contact.submittedAt,
  rowId: Math.floor(Math.random() * 9000) + 1000 // mock row ID
};

console.log(`[MOCK] Added to Google Sheet: ${contact.email} at row ${newRow.rowId}`);

return [{
  json: {
    ...contact,
    sheetRowId: newRow.rowId,
    addedToSheet: true
  }
}];

// Pass through existing contacts without modifying the sheet
// Just flag them so downstream nodes know context

const contact = $input.first().json;

console.log(`[INFO] Contact ${contact.email} already exists in sheet (since ${contact.existingSince}). Skipping append.`);

return [{
  json: {
    ...contact,
    addedToSheet: false,
    skipReason: 'Contact already exists in sheet'
  }
}];

// Mock sending a welcome email
// In production: replace with Gmail or SendGrid node

const contact = $input.first().json;

const emailPayload = {
  to: contact.email,
  subject: `Welcome, ${contact.name}! We received your message.`,
  body: `Hi ${contact.name},\n\nThank you for reaching out. We've received your message and will get back to you within 24 hours.\n\nYour message:\n"${contact.message}"\n\nBest regards,\nThe Team`,
  sentAt: new Date().toISOString()
};

console.log(`[MOCK] Welcome email sent to: ${contact.email}`);

return [{
  json: {
    ...contact,
    emailSent: true,
    emailSentAt: emailPayload.sentAt
  }
}];

// Mock posting a Slack notification to the team channel
// In production: replace with Slack node, channel #new-contacts

const contact = $input.first().json;

const status = contact.addedToSheet ? '🆕 New contact added to sheet' : '🔁 Returning contact (already in sheet)';

const slackMessage = {
  channel: '#new-contacts',
  text: `${status}\n*Name:* ${contact.name}\n*Email:* ${contact.email}\n*Message:* ${contact.message}\n*Submitted:* ${contact.submittedAt}`,
  postedAt: new Date().toISOString()
};

console.log(`[MOCK] Slack message posted to ${slackMessage.channel} for ${contact.email}`);

return [{
  json: {
    ...contact,
    slackPosted: true,
    slackPostedAt: slackMessage.postedAt
  }
}];

const contact = $input.first().json;

return [{
  json: {
    success: true,
    message: `Workflow completed for ${contact.email}`,
    summary: {
      name: contact.name,
      email: contact.email,
      addedToSheet: contact.addedToSheet,
      emailSent: contact.emailSent,
      slackPosted: contact.slackPosted,
      completedAt: new Date().toISOString()
    }
  }
}];

// Global error handler — catches failures from any node
// Logs the error and returns a structured failure response

const error = $input.first().json;
const errorMessage = error.message || error.error || 'Unknown error occurred';
const failedNode = error.node ? error.node.name : 'Unknown node';

console.error(`[ERROR] Workflow failed at node '${failedNode}': ${errorMessage}`);

// In production: also post to a #workflow-errors Slack channel or send an alert email

return [{
  json: {
    success: false,
    error: errorMessage,
    failedAt: failedNode,
    timestamp: new Date().toISOString(),
    hint: 'Check n8n execution logs for full stack trace'
  }
}];
